@import url("https://fonts.googleapis.com/css2?family=Figtree:wght@400;600;700&display=swap");
*, *::before, *::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

body {
  font-family: "Figtree", sans-serif;
  background: transparent;
}

.umr-wrap {
  padding: 0.5rem;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.umr-title {
  font-size: 18px;
  font-weight: 700;
  color: #05042E;
}

.umr-table-wrap {
  max-height: 280px;
  overflow-y: auto;
  border: 0.5px solid rgba(0, 0, 0, 0.08);
  border-radius: 8px;
}

.umr-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 13px;
}

.umr-table th {
  position: sticky;
  top: 0;
  text-align: left;
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.05em;
  color: #fff;
  background: #05042E;
  padding: 8px 10px;
}

.umr-table td {
  padding: 8px 10px;
  font-weight: 600;
  color: #05042E;
  border-bottom: 1px solid rgba(0, 0, 0, 0.06);
  cursor: pointer;
}

.umr-table tr:hover td {
  background: #f9f8f6;
}

.umr-table tr.selected td {
  background: rgba(70, 155, 192, 0.1);
}

.umr-empty-cell {
  color: #888780;
}

.umr-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  padding-top: 6px;
  border-top: 0.5px solid rgba(0, 0, 0, 0.08);
}

.umr-selected {
  font-size: 13px;
  font-weight: 700;
  color: #05042E;
}

.umr-btn {
  font-family: "Figtree", sans-serif;
  font-weight: 700;
  font-size: 13px;
  color: #05042E;
  background: #A3E851;
  border: none;
  border-radius: 6px;
  padding: 9px 18px;
  cursor: pointer;
}

.umr-btn:hover {
  background: #93d846;
}

.umr-btn:disabled {
  background: #E0DFE1;
  color: #aaa;
  cursor: not-allowed;
}

