function escHtml(str) {
  return String(str || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}
var selectedRow = null;
var currentRows = [];
function render(model) {
  currentRows = model.rows || [];
  var tbody = document.getElementById('umr-body');
  if (!currentRows.length) {
    tbody.innerHTML = '<tr><td colspan="5" class="umr-empty-cell" style="text-align:center;padding:1.5rem;">No unmatched rows</td></tr>';
    updateFooter();
    return;
  }
  tbody.innerHTML = currentRows.map(function (r) {
    var isSelected = selectedRow && selectedRow.asset_id === r.asset_id;
    return '<tr class="' + (isSelected ? 'selected' : '') + '" data-asset-id="' + r.asset_id + '">' + '<td>' + escHtml(r.asset_ref) + '</td>' + '<td>' + escHtml(r.serial_number || '—') + '</td>' + '<td>' + escHtml(r.item_type_name || '—') + '</td>' + '<td class="' + (r.make_name ? '' : 'umr-empty-cell') + '">' + escHtml(r.make_name || '—') + '</td>' + '<td class="' + (r.model_name ? '' : 'umr-empty-cell') + '">' + escHtml(r.model_name || '—') + '</td>' + '</tr>';
  }).join('');
  document.querySelectorAll('#umr-body tr[data-asset-id]').forEach(function (tr) {
    tr.addEventListener('click', function () {
      var id = Number(this.dataset.assetId);
      selectedRow = currentRows.find(function (r) {
        return r.asset_id === id;
      });
      render({
        rows: currentRows
      });
    });
  });
  updateFooter();
}
function updateFooter() {
  var label = document.getElementById('umr-selected');
  var btn = document.getElementById('umr-btn');
  if (selectedRow) {
    label.textContent = selectedRow.asset_ref;
    btn.disabled = false;
  } else {
    label.textContent = 'No row selected';
    btn.disabled = true;
  }
}
window.umrUpdateModel = function () {
  if (!selectedRow) return;
  appsmith.updateModel({
    selectedRow: selectedRow
  });
  appsmith.triggerEvent('onUpdateModel');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (m) {
  render(m);
});

